                            it.replaceWithText(getNewlineWithIndent(node.treeParent))
                        } else {
                            it.rawInsertBeforeMe(
                                PsiWhiteSpaceImpl(getNewlineWithIndent(node.treeParent)),
                            )
                        }
                    }
            }
        }
    }

